def sum_even_numbers(numbers):
    return sum(
        num
        for num in numbers
        if num % 2 == 0
    )

    # ہم ایک ہی طرح کی لسٹ کے لیے حساب شدہ نتیجہ کیش کرتے ہیں تاکہ دوبارہ حساب نہ کرنا پڑے۔

