def calculate_average(numbers):
    """دی گئی لسٹ کے نمبروں کا اوسط نکالیں۔"""
    if not numbers:
        return 0
    return sum(numbers) / len(numbers)

    # ہم ایک ہی طرح کے نمبروں کے اوسط کو محفوظ کرتے ہیں تاکہ دوبارہ استعمال میں کارکردگی بہتر ہو۔

